Refactor the `save` logic to improve concurrency and efficiency:
1. Use `saveMu` to ensure only one write operation happens at a time.
2. Release the store's read lock (`s.mu`) before performing JSON serialization and disk I/O. This prevents blocking other readers while the (potentially slow) I/O operations occur.
3. Note that as the number of chats grows, serializing the entire store on every message becomes increasingly expensive. Consider a more granular persistence strategy in the future.

```go
func (s *HistoryStore) save() {
	if s.path == "" {
		return
	}

	s.saveMu.Lock()
	defer s.saveMu.Unlock()

	s.mu.RLock()
	hf := historyFile{Chats: make(map[string][]Turn, len(s.buffers))}
	for chatID, buf := range s.buffers {
		hf.Chats[chatID] = buf.Turns()
	}
	s.mu.RUnlock()

	data, err := json.MarshalIndent(hf, "", "  ")
	if err != nil {
		slog.Error("failed to marshal history", "error", err)
		return
	}

	dir := filepath.Dir(s.path)
	tmp, err := os.CreateTemp(dir, ".history-*.tmp")
	if err != nil {
		slog.Error("failed to create temp file for history", "error", err)
		return
	}
	tmpName := tmp.Name()

	if _, err := tmp.Write(data); err != nil {
		tmp.Close()
		os.Remove(tmpName)
		slog.Error("failed to write history temp file", "error", err)
		return
	}
	if err := tmp.Close(); err != nil {
		os.Remove(tmpName)
		slog.Error("failed to close history temp file", "error", err)
		return
	}
	if err := os.Rename(tmpName, s.path); err != nil {
		os.Remove(tmpName)
		slog.Error("failed to rename history file", "error", err)
		return
	}
}
